/**
 * Helper function to generate a map of XOR sums to the maximum size of a subset
 * that achieves that XOR sum for a given array segment.
 * @param {number[]} arr The array segment.
 * @returns {Map<number, number>} A map where key is XOR sum and value is max subset size.
 */
function generateMap(arr) {
    const map = new Map();
    const N = arr.length;

    // Iterate through all 2^N subsets using a bitmask i
    for (let i = 0; i < (1 << N); i++) {
        let currentXor = 0;
        let currentSize = 0;

        // Calculate XOR sum and size for the subset represented by i
        for (let j = 0; j < N; j++) {
            if ((i >> j) & 1) {
                currentXor ^= arr[j];
                currentSize++;
            }
        }

        // Store the maximum size found for this XOR sum
        const existingSize = map.get(currentXor) || -1;
        if (currentSize > existingSize) {
            map.set(currentXor, currentSize);
        }
    }
    return map;
}

function solve(nums, target) {
    const N = nums.length;
    if (N === 0) {
        return target === 0 ? 0 : -1;
    }

    const N_A = Math.floor(N / 2);
    const A = nums.slice(0, N_A);
    const B = nums.slice(N_A);

    // 1. Generate maps for both halves
    const mapA = generateMap(A);
    const mapB = generateMap(B);

    let maxSize = -1;

    // 2. Combine results: Iterate over mapA and find complement in mapB
    for (const [xorA, sizeA] of mapA.entries()) {
        // We need xorA ^ xorB = target, so xorB = xorA ^ target
        const xorB_needed = xorA ^ target;

        if (mapB.has(xorB_needed)) {
            const sizeB = mapB.get(xorB_needed);
            const totalSize = sizeA + sizeB;

            if (totalSize > maxSize) {
                maxSize = totalSize;
            }
        }
    }

    // 3. Determine the result
    if (maxSize === -1) {
        // Target was never reachable
        return -1;
    } else {
        // Minimum removals = Total size - Maximum retained size
        return N - maxSize;
    }
}

