    val N = nums.size

    if (N == 0) {
        return if (target == 0L) 0L else -1L
    }

    val N_A = N / 2

    // Split nums into A and B
    val A = nums.sliceArray(0 until N_A)
    val B = nums.sliceArray(N_A until N)

    // 1. Generate maps for both halves
    val mapA = generateMap(A)
    val mapB = generateMap(B)

    var maxSize = -1

    // 2. Combine results: Iterate over mapA and find complement in mapB
    for ((xorA, sizeA) in mapA) {
        // We need xorA ^ xorB = target, so xorB = xorA ^ target
        val xorB_needed = xorA xor target

