            val sizeB = mapB[xorB_needed]!!
            val totalSize = sizeA + sizeB

            if (totalSize > maxSize) {
                maxSize = totalSize
            }
        }
    }

    // 3. Determine the result
    if (maxSize == -1) {
        // Target was never reachable
        return -1L
    } else {
        // Minimum removals = Total size - Maximum retained size
        return N.toLong() - maxSize.toLong()
    }
